PROMPT Before update 

SELECT COUNT(*) FROM PSP_PAYCHECK WHERE NET_AMOUNT is null;

-- Populate Net Amount for Paycheck
BEGIN
   FOR REC IN (
				  SELECT SUM(PAYCHECK_SPLIT_AMOUNT) AS NET_AMOUNT,PAYCHECK_FK FROM PSP_PAYCHECK_SPLIT GROUP BY PAYCHECK_FK
              )
   LOOP   
       UPDATE PSP_PAYCHECK set NET_AMOUNT=REC.NET_AMOUNT where
       PSP_PAYCHECK.PAYCHECK_SEQ=REC.PAYCHECK_FK;
   END LOOP;
END;

/
SHOW ERRORS;

COMMIT;

PROMPT After update 

SELECT COUNT(*) FROM PSP_PAYCHECK WHERE NET_AMOUNT is null;

PROMPT Before update Suffix

-- Populate Suffix in PSP_INDIVIDUAL
BEGIN
   FOR REC IN (
				  SELECT TITLE_SUFFIX AS SUFFIX,CONTACT_SEQ FROM PSP_CONTACT WHERE TITLE_SUFFIX IS NOT NULL
              )
   LOOP   
       UPDATE PSP_INDIVIDUAL set SUFFIX=REC.SUFFIX where
       PSP_INDIVIDUAL.INDIVIDUAL_SEQ =REC.CONTACT_SEQ;
   END LOOP;
END;
/
SHOW ERRORS;

COMMIT;

PROMPT After update Suffix

Prompt Column TITLE_SUFFIX;
ALTER TABLE PSP_CONTACT DROP COLUMN TITLE_SUFFIX;

PROMPT Before Creating PSP_CONTACT_AT Trigger

CREATE OR REPLACE TRIGGER PSP_CONTACT_AT
AFTER INSERT OR UPDATE ON PSP_CONTACT FOR EACH ROW
DECLARE
  v_company_fk VARCHAR2(255);
  v_creator_id VARCHAR2(30);
  v_modifier_id VARCHAR2(30);
BEGIN

SELECT CREATOR_ID INTO v_creator_id FROM PSP_INDIVIDUAL WHERE INDIVIDUAL_SEQ = :NEW.CONTACT_SEQ;
SELECT MODIFIER_ID INTO v_modifier_id FROM PSP_INDIVIDUAL WHERE INDIVIDUAL_SEQ = :NEW.CONTACT_SEQ;

  IF (UPDATING) THEN
     IF (((:NEW.AUTH_SIGNER_YN_IND <> :OLD.AUTH_SIGNER_YN_IND) AND :NEW.AUTH_SIGNER_YN_IND IS NOT NULL AND :OLD.AUTH_SIGNER_YN_IND IS NOT NULL) OR
         (:NEW.AUTH_SIGNER_YN_IND IS NULL AND :OLD.AUTH_SIGNER_YN_IND IS NOT NULL) OR
         (:NEW.AUTH_SIGNER_YN_IND IS NOT NULL AND :OLD.AUTH_SIGNER_YN_IND IS NULL) ) THEN
         BEGIN
            SELECT :NEW.COMPANY_FK INTO v_company_fk from DUAL;
         EXCEPTION
            WHEN NO_DATA_FOUND THEN v_company_fk := NULL;
            WHEN OTHERS THEN RAISE;
         END;

         IF v_company_fk IS NOT NULL THEN
            INSERT INTO PSP_PROPERTY_AUDIT
              (PROPERTY_AUDIT_SEQ, VERSION, CREATED_DATE, MODIFIED_DATE, CLASS_NAME, PROPERTY_NAME, OLD_PROPERTY_VALUE, NEW_PROPERTY_VALUE, OBJECT_IDENTIFIER, USER_ID, AUDIT_DATE, COMPANY_FK)
            VALUES
              (SYS_GUID(), 0, SYS_EXTRACT_UTC(SYSTIMESTAMP), SYS_EXTRACT_UTC(SYSTIMESTAMP), 'Contact', 'AuthSignerYnInd', TO_CHAR(:OLD.AUTH_SIGNER_YN_IND ), TO_CHAR(:NEW.AUTH_SIGNER_YN_IND ), :NEW.CONTACT_SEQ, v_modifier_id, SYS_EXTRACT_UTC(SYSTIMESTAMP), v_company_fk);
         END IF;
     END IF;

     IF (((:NEW.CONTACT_ROLE_CD <> :OLD.CONTACT_ROLE_CD) AND :NEW.CONTACT_ROLE_CD IS NOT NULL AND :OLD.CONTACT_ROLE_CD IS NOT NULL) OR
         (:NEW.CONTACT_ROLE_CD IS NULL AND :OLD.CONTACT_ROLE_CD IS NOT NULL) OR
         (:NEW.CONTACT_ROLE_CD IS NOT NULL AND :OLD.CONTACT_ROLE_CD IS NULL) ) THEN
         BEGIN
            SELECT :NEW.COMPANY_FK INTO v_company_fk from DUAL;
         EXCEPTION
            WHEN NO_DATA_FOUND THEN v_company_fk := NULL;
            WHEN OTHERS THEN RAISE;
         END;

         IF v_company_fk IS NOT NULL THEN
            INSERT INTO PSP_PROPERTY_AUDIT
              (PROPERTY_AUDIT_SEQ, VERSION, CREATED_DATE, MODIFIED_DATE, CLASS_NAME, PROPERTY_NAME, OLD_PROPERTY_VALUE, NEW_PROPERTY_VALUE, OBJECT_IDENTIFIER, USER_ID, AUDIT_DATE, COMPANY_FK)
            VALUES
              (SYS_GUID(), 0, SYS_EXTRACT_UTC(SYSTIMESTAMP), SYS_EXTRACT_UTC(SYSTIMESTAMP), 'Contact', 'ContactRoleCd', TO_CHAR(:OLD.CONTACT_ROLE_CD ), TO_CHAR(:NEW.CONTACT_ROLE_CD ), :NEW.CONTACT_SEQ, v_modifier_id, SYS_EXTRACT_UTC(SYSTIMESTAMP), v_company_fk);
         END IF;
     END IF;

     IF (((:NEW.FAX <> :OLD.FAX) AND :NEW.FAX IS NOT NULL AND :OLD.FAX IS NOT NULL) OR
         (:NEW.FAX IS NULL AND :OLD.FAX IS NOT NULL) OR
         (:NEW.FAX IS NOT NULL AND :OLD.FAX IS NULL) ) THEN
         BEGIN
            SELECT :NEW.COMPANY_FK INTO v_company_fk from DUAL;
         EXCEPTION
            WHEN NO_DATA_FOUND THEN v_company_fk := NULL;
            WHEN OTHERS THEN RAISE;
         END;

         IF v_company_fk IS NOT NULL THEN
            INSERT INTO PSP_PROPERTY_AUDIT
              (PROPERTY_AUDIT_SEQ, VERSION, CREATED_DATE, MODIFIED_DATE, CLASS_NAME, PROPERTY_NAME, OLD_PROPERTY_VALUE, NEW_PROPERTY_VALUE, OBJECT_IDENTIFIER, USER_ID, AUDIT_DATE, COMPANY_FK)
            VALUES
              (SYS_GUID(), 0, SYS_EXTRACT_UTC(SYSTIMESTAMP), SYS_EXTRACT_UTC(SYSTIMESTAMP), 'Contact', 'Fax', TO_CHAR(:OLD.FAX ), TO_CHAR(:NEW.FAX ), :NEW.CONTACT_SEQ, v_modifier_id, SYS_EXTRACT_UTC(SYSTIMESTAMP), v_company_fk);
         END IF;
     END IF;

     IF (((:NEW.JOB_TITLE <> :OLD.JOB_TITLE) AND :NEW.JOB_TITLE IS NOT NULL AND :OLD.JOB_TITLE IS NOT NULL) OR
         (:NEW.JOB_TITLE IS NULL AND :OLD.JOB_TITLE IS NOT NULL) OR
         (:NEW.JOB_TITLE IS NOT NULL AND :OLD.JOB_TITLE IS NULL) ) THEN
         BEGIN
            SELECT :NEW.COMPANY_FK INTO v_company_fk from DUAL;
         EXCEPTION
            WHEN NO_DATA_FOUND THEN v_company_fk := NULL;
            WHEN OTHERS THEN RAISE;
         END;

         IF v_company_fk IS NOT NULL THEN
            INSERT INTO PSP_PROPERTY_AUDIT
              (PROPERTY_AUDIT_SEQ, VERSION, CREATED_DATE, MODIFIED_DATE, CLASS_NAME, PROPERTY_NAME, OLD_PROPERTY_VALUE, NEW_PROPERTY_VALUE, OBJECT_IDENTIFIER, USER_ID, AUDIT_DATE, COMPANY_FK)
            VALUES
              (SYS_GUID(), 0, SYS_EXTRACT_UTC(SYSTIMESTAMP), SYS_EXTRACT_UTC(SYSTIMESTAMP), 'Contact', 'JobTitle', TO_CHAR(:OLD.JOB_TITLE ), TO_CHAR(:NEW.JOB_TITLE ), :NEW.CONTACT_SEQ, v_modifier_id, SYS_EXTRACT_UTC(SYSTIMESTAMP), v_company_fk);
         END IF;
     END IF;

     IF (((:NEW.SOURCE_CONTACT_ID <> :OLD.SOURCE_CONTACT_ID) AND :NEW.SOURCE_CONTACT_ID IS NOT NULL AND :OLD.SOURCE_CONTACT_ID IS NOT NULL) OR
         (:NEW.SOURCE_CONTACT_ID IS NULL AND :OLD.SOURCE_CONTACT_ID IS NOT NULL) OR
         (:NEW.SOURCE_CONTACT_ID IS NOT NULL AND :OLD.SOURCE_CONTACT_ID IS NULL) ) THEN
         BEGIN
            SELECT :NEW.COMPANY_FK INTO v_company_fk from DUAL;
         EXCEPTION
            WHEN NO_DATA_FOUND THEN v_company_fk := NULL;
            WHEN OTHERS THEN RAISE;
         END;

         IF v_company_fk IS NOT NULL THEN
            INSERT INTO PSP_PROPERTY_AUDIT
              (PROPERTY_AUDIT_SEQ, VERSION, CREATED_DATE, MODIFIED_DATE, CLASS_NAME, PROPERTY_NAME, OLD_PROPERTY_VALUE, NEW_PROPERTY_VALUE, OBJECT_IDENTIFIER, USER_ID, AUDIT_DATE, COMPANY_FK)
            VALUES
              (SYS_GUID(), 0, SYS_EXTRACT_UTC(SYSTIMESTAMP), SYS_EXTRACT_UTC(SYSTIMESTAMP), 'Contact', 'SourceContactId', TO_CHAR(:OLD.SOURCE_CONTACT_ID ), TO_CHAR(:NEW.SOURCE_CONTACT_ID ), :NEW.CONTACT_SEQ, v_modifier_id, SYS_EXTRACT_UTC(SYSTIMESTAMP), v_company_fk);
         END IF;
     END IF;

     IF (((:NEW.TITLE <> :OLD.TITLE) AND :NEW.TITLE IS NOT NULL AND :OLD.TITLE IS NOT NULL) OR
         (:NEW.TITLE IS NULL AND :OLD.TITLE IS NOT NULL) OR
         (:NEW.TITLE IS NOT NULL AND :OLD.TITLE IS NULL) ) THEN
         BEGIN
            SELECT :NEW.COMPANY_FK INTO v_company_fk from DUAL;
         EXCEPTION
            WHEN NO_DATA_FOUND THEN v_company_fk := NULL;
            WHEN OTHERS THEN RAISE;
         END;

         IF v_company_fk IS NOT NULL THEN
            INSERT INTO PSP_PROPERTY_AUDIT
              (PROPERTY_AUDIT_SEQ, VERSION, CREATED_DATE, MODIFIED_DATE, CLASS_NAME, PROPERTY_NAME, OLD_PROPERTY_VALUE, NEW_PROPERTY_VALUE, OBJECT_IDENTIFIER, USER_ID, AUDIT_DATE, COMPANY_FK)
            VALUES
              (SYS_GUID(), 0, SYS_EXTRACT_UTC(SYSTIMESTAMP), SYS_EXTRACT_UTC(SYSTIMESTAMP), 'Contact', 'Title', TO_CHAR(:OLD.TITLE ), TO_CHAR(:NEW.TITLE ), :NEW.CONTACT_SEQ, v_modifier_id, SYS_EXTRACT_UTC(SYSTIMESTAMP), v_company_fk);
         END IF;
     END IF;

  END IF;
END;
/
SHOW ERRORS;

PROMPT After Creating PSP_CONTACT_AT Trigger


PROMPT Before Creating PSP_INDIVIDUAL_AT Trigger

CREATE OR REPLACE TRIGGER PSP_INDIVIDUAL_AT
AFTER INSERT OR UPDATE ON PSP_INDIVIDUAL FOR EACH ROW
DECLARE
  v_company_fk VARCHAR2(255);
  v_creator_id VARCHAR2(30);
  v_modifier_id VARCHAR2(30);
BEGIN

SELECT :NEW.CREATOR_ID INTO v_creator_id FROM DUAL;
SELECT :NEW.MODIFIER_ID INTO v_modifier_id FROM DUAL;

  IF (UPDATING) THEN
     IF (((:NEW.SUFFIX <> :OLD.SUFFIX) AND :NEW.SUFFIX IS NOT NULL AND :OLD.SUFFIX IS NOT NULL) OR
         (:NEW.SUFFIX IS NULL AND :OLD.SUFFIX IS NOT NULL) OR
         (:NEW.SUFFIX IS NOT NULL AND :OLD.SUFFIX IS NULL) ) THEN
         BEGIN
            SELECT t1.COMPANY_FK INTO v_company_fk from PSP_CONTACT t1 WHERE t1.CONTACT_SEQ = :NEW.INDIVIDUAL_SEQ;
         EXCEPTION
            WHEN NO_DATA_FOUND THEN v_company_fk := NULL;
            WHEN OTHERS THEN RAISE;
         END;

         IF v_company_fk IS NOT NULL THEN
            INSERT INTO PSP_PROPERTY_AUDIT
              (PROPERTY_AUDIT_SEQ, VERSION, CREATED_DATE, MODIFIED_DATE, CLASS_NAME, PROPERTY_NAME, OLD_PROPERTY_VALUE, NEW_PROPERTY_VALUE, OBJECT_IDENTIFIER, USER_ID, AUDIT_DATE, COMPANY_FK)
            VALUES
              (SYS_GUID(), 0, SYS_EXTRACT_UTC(SYSTIMESTAMP), SYS_EXTRACT_UTC(SYSTIMESTAMP), 'Individual', 'Suffix', TO_CHAR(:OLD.SUFFIX ), TO_CHAR(:NEW.SUFFIX ), :NEW.INDIVIDUAL_SEQ, v_modifier_id, SYS_EXTRACT_UTC(SYSTIMESTAMP), v_company_fk);
         END IF;
     END IF;

  END IF;
END;
/
SHOW ERRORS;
PROMPT After Creating PSP_INDIVIDUAL_AT Trigger